const response = $input.first().json;
const content = response.content?.[0]?.text || '[]';
let changes;
try {
  const jsonMatch = content.match(/\[.*\]/s);
  changes = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{ json: { changes_found: 0 } }];
}
return changes.map(c => ({ json: c }));
